/*
<!-- Constants -->
<Variable name="latoNormal14" description="Lato Normal 14" type="font" default="400 14px Lato, sans-serif" hideEditor="true"  value="400 14px Lato, sans-serif"/>
<Variable name="latoNormal16" description="Lato Normal 16" type="font" default="400 16px Lato, sans-serif" hideEditor="true"  value="400 16px Lato, sans-serif"/>
<Variable name="latoNormal20" description="Lato Normal 20" type="font" default="400 20px Lato, sans-serif" hideEditor="true"  value="400 20px Lato, sans-serif"/>
<Variable name="latoReguler14" description="Lato Reguler 14" type="font" default="500 14px Lato, sans-serif" hideEditor="true"  value="500 14px Lato, sans-serif"/>
<Variable name="latoReguler16" description="Lato Reguler 16" type="font" default="500 16px Lato, sans-serif" hideEditor="true"  value="500 16px Lato, sans-serif"/>
<Variable name="latoReguler20" description="Lato Reguler 20" type="font" default="500 20px Lato, sans-serif" hideEditor="true"  value="500 20px Lato, sans-serif"/>
<Variable name="latoBold14" description="Lato Bold 14" type="font" default="700 14px Lato, sans-serif" hideEditor="true"  value="700 14px Lato, sans-serif"/>
<Variable name="latoBold16" description="Lato Bold 16" type="font" default="700 16px Lato, sans-serif" hideEditor="true"  value="700 16px Lato, sans-serif"/>
<Variable name="latoBold24" description="Lato Bold 24" type="font" default="700 24px Lato, sans-serif" hideEditor="true"  value="700 24px Lato, sans-serif"/>
<Variable name="latoBold36" description="Lato Bold 36" type="font" default="700 36px Lato, sans-serif" hideEditor="true"  value="700 36px Lato, sans-serif"/>
<Variable name="latoBold48" description="Lato Bold 48" type="font" default="700 48px Lato, sans-serif" hideEditor="true"  value="700 48px Lato, sans-serif"/>
<Variable name="latoExtrabold24" description="Lato Extrabold 24" type="font" default="900 24px Lato, sans-serif" hideEditor="true"  value="900 24px Lato, sans-serif"/>

<Variable name="keycolor" description="Main Color" type="color" default="#e50914"  value="#e50914"/>

<Group description="Backgrounds" selector="html,body">
  <Variable name="background.font" description="Main font" type="font" default="$(latoNormal16)"  value="400 16px Lato, sans-serif"/>
  <Variable name="body.background" description="Background" color="$(background.color)" type="background" default="$(color) none repeat scroll top left"  value="$(color) url() no-repeat scroll top center /* Credit: Temabanua (https://www.temabanua.com/) */;"/>
  <Variable name="mobile" description="Body Background Bar" type="color" default="#1a1a1a"  value="#1a1a1a"/>
  <Variable name="background.link.color" description="Background link color" type="color" default="#2abdbb"  value="#2abdbb"/>
  <Variable name="background.color" description="Background color" type="color" default="#000"  value="#000000"/>
  <Variable name="background.text.color" description="Background font color" type="color" default="#fff"  value="#ffffff"/>
  <Variable name="background.meta.color" description="Background meta color" type="color" default="#a0a0a0"  value="#a0a0a0"/>
  <Variable name="background.form.color" description="Background form color" type="color" default="#18191c"  value="#18191c"/>
</Group>

<Group description="Header" selector=".temabanua-header">
  <Variable name="head.background.color" description="Header background color" type="color" default="#111111" value="#111111"/>
  <Variable name="head.background.hover" description="Header background hover" type="color" default="#0a0a0a" value="#0a0a0a"/>
  <Variable name="head.text.color" description="Header font color" type="color" default="#dadada" value="#dadada"/>
  <Variable name="posts.title.color" description="Font color" type="color" default="#ffffff"  value="#ffffff"/>
</Group>

<Group description="Navigasi" selector="#blog-pager">
  <Variable name="navigasi.background.color" description="Navigasi background color" type="color" default="#151c38" value="#151c38"/>
  <Variable name="navigasi.hover.color" description="Navigasi hover color" type="color" default="#192247" value="#192247"/>
  <Variable name="navigasi.title.color" description="Navigasi font color" type="color" default="#ffffff" value="#ffffff"/>
</Group>

<Group description="Footer" selector=".temabanua-footer">
  <Variable name="footer.background.color" description="Footer background color" type="color" default="#2a0907" value="#2a0907"/>
  <Variable name="footer.border.color" description="Footer border color" type="color" default="#401616" value="#401616"/>
  <Variable name="footer.title.color" description="Footer font color" type="color" default="#d0d0d0" value="#d0d0d0"/>
</Group>

<Variable name="body.background.color" description="Comments Background" hideEditor="true" type="color" default="transparent"  value="transparent"/>
<Variable name="body.title.color" description="Comments Color" hideEditor="true" type="color" default="#2abdbb" value="#2abdbb"/>
<Variable name="body.text.color" description="Comments Text Color" hideEditor="true" type="color" default="$(posts.title.color)"  value="#ffffff"/>
<Variable name="body.link.color" description="Comments Link Color" hideEditor="true" type="color" default="#2abdbb"  value="#2abdbb"/>
<Variable name="body.text.font" description="Comments Font 1" hideEditor="true" type="font" default="normal 400 15px roboto, Arial, sans-serif !important"  value="normal 400 15px roboto, Arial, sans-serif !important"/>
<Variable name="body.action.font.large" description="Comments Font 2" hideEditor="true" type="font" default="normal 700 15px roboto, Arial, sans-serif !important"  value="normal 700 15px roboto, Arial, sans-serif !important"/>
*/

/*!************************************************
 * Blogger Template Style
 * Name      : Animed
 * Version   : Free Version - https://www.temabanua.com/p/licenses.html
 * Creator   : Rian seo - https://www.temabanua.com
