:root {
--main-link:$(background.link.color);
--main-font:$(background.font);
--main-color:$(keycolor);
--body-color:$(background.color);
--body-text:$(background.text.color);
--body-meta:$(background.meta.color);
--head-height:3.75rem;
--head-color:$(head.background.color);
--head-hover:$(head.background.hover);
--head-text:$(head.text.color);
--post-title:$(posts.title.color);
--search-form:$(background.form.color);
--loadmore-color:$(navigasi.background.color);
--loadmore-text:$(navigasi.title.color);
--loadmore-hover:$(navigasi.hover.color);
--footer-color:$(footer.background.color);
--footer-border:$(footer.border.color);
--footer-title:$(footer.title.color);
--line-footer-m:rgba($(posts.title.color.red),$(posts.title.color.green),$(posts.title.color.blue),0.12);
--bg-label-trans: rgba($(posts.title.color.red),$(posts.title.color.green),$(posts.title.color.blue),0.2);
}

