/* ===== EPISODE LIST ===== */
.episode-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 8px;
  margin: 10px 0;
}
@media (max-width: 768px) {
  .episode-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}
@media (max-width: 480px) {
  .episode-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}
.ep-btn {
  display: block;
  padding: 8px 4px;
  background: #111;
  color: #fff;
  text-align: center;
  font-size: 13px;
  border-radius: 4px;
  text-decoration: none;
  transition: background 0.2s;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.ep-btn:hover {
  background: var(--main-color, #e50914);
  color: #fff;
}

/* ===== VERTICAL EPISODE LIST ===== */
.episode-list-vertical {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin: 15px 0;
}
.episode-item-vertical {
  display: flex;
  gap: 12px;
  text-decoration: none;
  color: inherit;
  padding: 10px;
  border-radius: 4px;
  transition: background 0.2s;
}
.episode-item-vertical:hover {
  background: rgba(255, 255, 255, 0.05);
}
.ep-thumb-vertical {
  flex: 0 0 80px;
  height: 60px;
  border-radius: 4px;
  overflow: hidden;
  background: #222;
}
.ep-thumb-vertical img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.ep-info-vertical {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  min-width: 0;
}
.ep-title-vertical {
  font-size: 14px;
  font-weight: 600;
  color: #fff;
  margin-bottom: 4px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.ep-meta-vertical {
  font-size: 12px;
  color: #aaa;
  display: flex;
  gap: 8px;
  align-items: center;
}
.ep-label {
  color: var(--main-color, #e50914);
  font-weight: 600;
}
.ep-time {
  color: #888;
}
/* ===== END VERTICAL EPISODE LIST ===== */
/* ===== END EPISODE LIST ===== */
.read-more{
  font-weight:600;
  color:var(--loadmore-text);
  padding:0 1rem;
  text-decoration:none;
  background-color:var(--loadmore-color);
  border-radius:4px;
  display:inline-flex;
  align-items:center;
  height:3rem;
  justify-content:center;
  min-width:7.5rem;
  position:relative;
  transition-duration:.2s;
  transition-property:color,background-color,box-shadow;
  transition-timing-function:ease;
  -webkit-user-select:none;
  user-select:none;
  line-height:1.5rem;
  font-size:1rem;
}
.read-more:hover{
  background-color:var(--loadmore-hover);
}
.new-episodes-list{
  display:flex;
  flex-direction:column;
  gap:1.5rem;
  margin:1.5rem 0;
}
.new-episodes-list .index-post{
  display:grid;
  grid-template-columns:120px 1fr;
  gap:1rem;
  align-items:flex-start;
}
.new-episodes-list .content-image-box{
  height:90px;
  width:120px;
  border-radius:4px;
  overflow:hidden;
}
.new-episodes-list .content-image-size{
  width:100%;
  height:100%;
  object-fit:cover;
}
.new-episodes-list .content-post-info{
  padding:0;
}
.new-episodes-list .content-post-info h2{
  font-size:1rem;
  line-height:1.25rem;
  margin:0 0 0.5rem 0;
  font-weight:700;
}
.new-episodes-list .content-post-info .post-meta{
  display:flex;
  flex-direction:column;
  gap:0.25rem;
}
.new-episodes-list .content-post-label span{
  color:var(--main-color);
  font-size:0.75rem;
  font-weight:600;
  display:inline-flex;
  align-items:center;
  gap:0.25rem;
}
.new-episodes-list .content-post-label span:before{
  content:'▶';
  font-size:0.625rem;
}
.new-episodes-list .content-post-author{
  font-size:0.875rem;
  color:var(--body-meta);
}
.new-episodes-list .content-post-date{
  font-size:0.875rem;
  color:var(--main-link);
  font-weight:600;
}

